import { useTable, BaseTable, selectionColumn } from '@gravity-ui/table';
import type { ColumnDef } from '@gravity-ui/table';

const columns: ColumnDef<Item>[] = [selectionColumn as ColumnDef<Item>, ...myColumns];

const [rowSelection, setRowSelection] = React.useState({});
