import { useTable, useRowVirtualizer, BaseTable } from '@gravity-ui/table';

const table = useTable({ columns, data, getRowId: (item) => item.id });
const containerRef = React.useRef(null);
const rowVirtualizer = useRowVirtualizer({
  count: table.getRowModel().rows.length,
  estimateSize: () => 20,
  overscan: 5,
  getScrollElement: () => containerRef.current,
});
return (
  <div ref={containerRef} style={{ height: '90vh', overflow: 'auto' }}>
    <BaseTable table={table} rowVirtualizer={rowVirtualizer} stickyHeader />
  </div>
);

