import { ReorderingProvider, BaseTable, useTable, dragHandleColumn } from '@gravity-ui/table';

const [data, setData] = React.useState(originalData);
const table = useTable({ columns: [dragHandleColumn, ...cols], data, getRowId: (item) => item.id });

const handleReorder = ({ draggedItemKey, baseItemKey }) => {
  setData(prev => {
    const next = prev.slice();
    const idx = next.findIndex(item => item.id === draggedItemKey);
    const [dragged] = next.splice(idx, 1);
    const insertIdx = next.findIndex(item => item.id === baseItemKey);
    next.splice(insertIdx + 1, 0, dragged);
    return next;
  });
};

return (
  <ReorderingProvider table={table} onReorder={handleReorder}>
    <BaseTable table={table} />
  </ReorderingProvider>
);

